"""Auth session routes and browser input pages."""

from __future__ import annotations

from datetime import timedelta
from typing import Any

from fastapi import APIRouter, BackgroundTasks, Depends, Request
from fastapi.responses import HTMLResponse, RedirectResponse, Response

from authsome.auth import AuthService
from authsome.auth.input_provider import InputField
from authsome.auth.models.enums import FlowType
from authsome.auth.sessions import AuthSession, AuthSessionStatus, AuthSessionStore
from authsome.server.routes._deps import get_auth_service, get_auth_sessions, get_server_base_url
from authsome.server.schemas import (
    AuthSessionResponse,
    NoneAction,
    OpenUrlAction,
    ResumeAuthSessionRequest,
    StartAuthSessionRequest,
)
from authsome.server.ui import pages
from authsome.server.urls import build_auth_input_url, build_callback_url, build_device_url
from authsome.utils import utc_now

router = APIRouter(prefix="/auth", tags=["auth"])


@router.post("/sessions", response_model=AuthSessionResponse)
def start_session(
    body: StartAuthSessionRequest,
    background_tasks: BackgroundTasks,
    auth: AuthService = Depends(get_auth_service),
    sessions: AuthSessionStore = Depends(get_auth_sessions),
    server_base_url: str = Depends(get_server_base_url),
) -> AuthSessionResponse:
    definition = auth.get_provider(body.provider)
    flow = FlowType(body.flow) if body.flow else definition.flow
    session = sessions.create(
        provider=body.provider,
        profile=auth.identity,
        connection_name=body.connection,
        flow_type=flow.value,
    )
    session.payload["force"] = body.force
    session.payload["callback_url_override"] = build_callback_url(server_base_url)
    if body.scopes is not None:
        session.payload["requested_scopes"] = body.scopes
    if body.base_url is not None:
        session.payload["base_url"] = body.base_url

    if not body.force:
        try:
            existing = auth.get_connection(body.provider, body.connection)
            if auth._connection_is_valid(existing) and auth._requested_context_matches(
                existing,
                scopes=body.scopes,
                base_url=body.base_url,
            ):
                session.state = AuthSessionStatus.COMPLETED
                session.status_message = "Already connected"
                return _session_response(session, server_base_url)
        except Exception:
            pass

    fields = auth.get_required_inputs(session, scopes=body.scopes, base_url=body.base_url)
    if fields:
        session.state = AuthSessionStatus.WAITING_FOR_USER
        session.payload["input_fields"] = [_field_to_payload(field) for field in fields]
        return _session_response(session, server_base_url)

    auth.begin_login_flow(
        session=session,
        scopes=body.scopes,
        force=body.force,
        base_url=body.base_url,
    )
    if FlowType(session.flow_type) == FlowType.DEVICE_CODE:
        _update_device_code_expiry(sessions, session)
        background_tasks.add_task(auth.background_resume, session)
    sessions.index_oauth_state(session)
    return _session_response(session, server_base_url)


@router.get("/sessions/{session_id}", response_model=AuthSessionResponse)
def get_session(
    session_id: str,
    sessions: AuthSessionStore = Depends(get_auth_sessions),
    server_base_url: str = Depends(get_server_base_url),
) -> AuthSessionResponse:
    return _session_response(sessions.get(session_id), server_base_url)


@router.post("/sessions/{session_id}/resume", response_model=AuthSessionResponse)
def resume_session(
    session_id: str,
    body: ResumeAuthSessionRequest,
    auth: AuthService = Depends(get_auth_service),
    sessions: AuthSessionStore = Depends(get_auth_sessions),
    server_base_url: str = Depends(get_server_base_url),
) -> AuthSessionResponse:
    session = sessions.get(session_id)
    try:
        record = auth.resume_login_flow(session, body.data)
        if record is None:
            session.state = AuthSessionStatus.WAITING_FOR_USER
        else:
            session.state = AuthSessionStatus.COMPLETED
            session.status_message = "Login successful"
    except Exception as exc:
        session.state = AuthSessionStatus.FAILED
        session.error_message = str(exc)
        raise
    return _session_response(session, server_base_url)


@router.get("/callback/oauth", response_class=HTMLResponse)
def oauth_callback(
    request: Request,
    auth: AuthService = Depends(get_auth_service),
    sessions: AuthSessionStore = Depends(get_auth_sessions),
) -> Response:
    state = request.query_params.get("state")
    if not state:
        return HTMLResponse(pages.message_page("Authentication failed", "Missing OAuth state."), status_code=400)
    try:
        session = sessions.get_by_oauth_state(state)
    except KeyError:
        return HTMLResponse(
            pages.message_page("Authentication session expired", "Please run authsome login again."),
            status_code=400,
        )
    callback_data = dict(request.query_params)
    try:
        auth.resume_login_flow(session, callback_data)
        session.state = AuthSessionStatus.COMPLETED
        session.status_message = "Login successful"
    except Exception as exc:
        session.state = AuthSessionStatus.FAILED
        session.error_message = str(exc)
        return HTMLResponse(pages.message_page("Authentication failed", str(exc)), status_code=400)
    if return_url := session.payload.get("return_url"):
        return RedirectResponse(str(return_url), status_code=303)
    return HTMLResponse(pages.message_page("Authentication successful", "You can close this window."))


@router.get("/sessions/{session_id}/input", response_class=HTMLResponse)
def input_page(
    session_id: str,
    auth: AuthService = Depends(get_auth_service),
    sessions: AuthSessionStore = Depends(get_auth_sessions),
) -> HTMLResponse:
    try:
        session = sessions.get(session_id)
    except KeyError:
        return HTMLResponse(
            pages.message_page("Authentication session expired", "Please run authsome login again."),
            status_code=404,
        )
    definition = auth.get_provider(session.provider)
    fields = session.payload.get("input_fields", [])
    return HTMLResponse(pages.input_page(session.session_id, definition.display_name, definition.docs, fields))


@router.get("/sessions/{session_id}/device", response_class=HTMLResponse)
def device_page(
    session_id: str,
    auth: AuthService = Depends(get_auth_service),
    sessions: AuthSessionStore = Depends(get_auth_sessions),
) -> HTMLResponse:
    try:
        session = sessions.get(session_id)
    except KeyError:
        return HTMLResponse(
            pages.message_page("Authentication session expired", "Please run authsome login again."),
            status_code=404,
        )
    user_code = session.payload.get("user_code")
    verification_uri = session.payload.get("verification_uri")
    verification_uri_complete = session.payload.get("verification_uri_complete")
    if not user_code or not verification_uri:
        return HTMLResponse(
            pages.message_page("Invalid session", "This session does not have a device code."), status_code=400
        )
    definition = auth.get_provider(session.provider)
    return HTMLResponse(
        pages.device_code_page(definition.display_name, user_code, verification_uri, verification_uri_complete)
    )


@router.post("/sessions/{session_id}/input")
async def submit_input(
    session_id: str,
    request: Request,
    background_tasks: BackgroundTasks,
    auth: AuthService = Depends(get_auth_service),
    sessions: AuthSessionStore = Depends(get_auth_sessions),
    server_base_url: str = Depends(get_server_base_url),
):
    session = sessions.get(session_id)
    form = await request.form()
    inputs = {key: str(value) for key, value in form.items()}

    auth.save_inputs(session, inputs)

    flow = FlowType(session.flow_type)
    if flow == FlowType.API_KEY:
        auth.resume_login_flow(session, {})
        session.state = AuthSessionStatus.COMPLETED
        session.status_message = "Login successful"
        if return_url := session.payload.get("return_url"):
            return RedirectResponse(str(return_url), status_code=303)
        return HTMLResponse(pages.message_page("Authentication successful", "You can close this window."))

    session.payload["callback_url_override"] = build_callback_url(server_base_url)
    auth.begin_login_flow(
        session=session,
        scopes=session.payload.get("requested_scopes"),
        force=bool(session.payload.get("force", False)),
        base_url=session.payload.get("base_url"),
    )
    if flow == FlowType.DEVICE_CODE:
        _update_device_code_expiry(sessions, session)
        background_tasks.add_task(auth.background_resume, session)
        if session.payload.get("user_code") and session.payload.get("verification_uri"):
            return RedirectResponse(url=build_device_url(server_base_url, session.session_id), status_code=303)

    sessions.index_oauth_state(session)

    auth_url = session.payload.get("auth_url")
    if auth_url:
        return RedirectResponse(str(auth_url), status_code=303)
    return HTMLResponse(pages.message_page("Authentication started", "Return to your terminal to continue."))


def _update_device_code_expiry(sessions: AuthSessionStore, session: AuthSession) -> None:
    if "expires_in" in session.payload:
        try:
            session.expires_at = utc_now() + timedelta(seconds=int(session.payload["expires_in"]))
        except ValueError:
            pass


def _session_response(session: AuthSession, server_base_url: str) -> AuthSessionResponse:
    action: OpenUrlAction | NoneAction = NoneAction()
    input_fields = session.payload.get("input_fields")
    if input_fields and session.state != AuthSessionStatus.COMPLETED:
        action = OpenUrlAction(type="open_url", url=build_auth_input_url(server_base_url, session.session_id))
    elif session.payload.get("auth_url"):
        action = OpenUrlAction(type="open_url", url=str(session.payload["auth_url"]))
    elif session.payload.get("verification_uri") and session.payload.get("user_code"):
        action = OpenUrlAction(
            type="open_url",
            url=build_device_url(server_base_url, session.session_id),
        )
    return AuthSessionResponse(
        id=session.session_id,
        provider=session.provider,
        connection=session.connection_name,
        status=session.state,
        message=session.status_message,
        error=session.error_message,
        created_at=session.created_at,
        expires_at=session.expires_at,
        next_action=action,
    )


def _field_to_payload(field: InputField) -> dict[str, Any]:
    return field.model_dump(mode="json", exclude_none=True)

"""Proxy support routes."""

from __future__ import annotations

from urllib.parse import urlparse

from fastapi import APIRouter, Depends

from authsome.auth import AuthService
from authsome.server.routes._deps import get_auth_service
from authsome.server.schemas import (
    CredentialResolutionRequest,
    CredentialResolutionResponse,
    ProviderRoute,
    ProxyRoutesResponse,
)

router = APIRouter(tags=["proxy"])


@router.get("/proxy/routes", response_model=ProxyRoutesResponse)
def proxy_routes(auth: AuthService = Depends(get_auth_service)) -> ProxyRoutesResponse:
    routes: list[ProviderRoute] = []
    for provider_group in auth.list_connections():
        provider_name = provider_group["name"]
        try:
            definition = auth.get_provider(provider_name)
        except Exception:
            continue
        if not definition.host_url:
            continue
        routes.append(
            ProviderRoute(
                provider=provider_name,
                connection=None,
                host_url=definition.host_url,
                auth_endpoint_paths=sorted(_auth_endpoint_paths(definition)),
            )
        )
    routes.sort(key=lambda route: (route.host_url.startswith("regex:"), route.provider))
    return ProxyRoutesResponse(routes=routes)


@router.post("/credentials/resolve", response_model=CredentialResolutionResponse)
def resolve_credentials(
    body: CredentialResolutionRequest,
    auth: AuthService = Depends(get_auth_service),
) -> CredentialResolutionResponse:
    connection = auth.resolve_connection_name(body.provider, body.connection)
    record = auth.get_connection(body.provider, connection)
    headers = auth.get_auth_headers(body.provider, connection)
    return CredentialResolutionResponse(
        provider=body.provider,
        connection=connection,
        headers=headers,
        expires_at=record.expires_at,
    )


def _auth_endpoint_paths(provider) -> set[str]:
    if not provider.oauth:
        return set()
    paths: set[str] = set()
    for raw_url in [
        provider.oauth.authorization_url,
        provider.oauth.token_url,
        provider.oauth.revocation_url,
        provider.oauth.device_authorization_url,
        provider.oauth.registration_endpoint,
    ]:
        if not raw_url:
            continue
        parsed = urlparse(raw_url)
        paths.add(parsed.path or "/")
    return paths

"""Mitmproxy addon and server lifecycle for header injection."""

from __future__ import annotations

import re
import threading
from dataclasses import dataclass
from datetime import datetime, timedelta
from pathlib import Path
from typing import Protocol
from urllib.parse import urlparse

from loguru import logger
from mitmproxy import ctx as mitmproxy_ctx
from mitmproxy import http
from mitmproxy.options import Options
from mitmproxy.tools.dump import DumpMaster

from authsome.proxy.router import RouteMatch
from authsome.utils import utc_now

_LOOPBACK_HOSTS = frozenset({"127.0.0.1", "localhost", "::1"})
_HEADER_REFRESH_WINDOW = timedelta(seconds=300)
_REGEX_HOST_PREFIX = "regex:"
_HOST_SPECIFICITY_REGEX = 0
_HOST_SPECIFICITY_EXACT = 1


class ProxyClient(Protocol):
    def list_connections(self) -> dict: ...

    def get_provider(self, provider: str) -> dict: ...

    def resolve_credentials(self, **kwargs) -> dict: ...

    def proxy_routes(self) -> dict: ...


@dataclass(frozen=True)
class _RouteTarget:
    match: RouteMatch
    path_prefix: str | None
    auth_endpoint_paths: frozenset[str]
    host_specificity: int


@dataclass(frozen=True)
class _RegexRouteTarget:
    host_pattern: re.Pattern[str]
    target: _RouteTarget


@dataclass(frozen=True)
class _HeaderCacheEntry:
    headers: dict[str, str]
    expires_at: datetime | None


class ProxyRouter:
    """Cached provider route table for proxy request matching."""

    def __init__(self, client: ProxyClient) -> None:
        self._routes_by_host, self._regex_routes = self._build_routes(client)

    def route(self, scheme: str, host: str, port: int, path: str) -> RouteMatch | None:
        """Return a route for a request, or None when the request should pass through."""
        if scheme.lower() != "https":
            return None

        normalized_host = _normalize_host(host)
        if normalized_host in _LOOPBACK_HOSTS:
            return None

        request_path = _request_path(path)
        candidate_targets = list(self._routes_by_host.get(normalized_host, ()))
        candidate_targets.extend(
            route.target for route in self._regex_routes if route.host_pattern.fullmatch(normalized_host)
        )

        matching_targets = [
            target
            for target in candidate_targets
            if _path_matches_prefix(request_path, target.path_prefix) and request_path not in target.auth_endpoint_paths
        ]

        if len(matching_targets) == 0:
            return None

        best_specificity = max(_target_specificity(target) for target in matching_targets)
        best_targets = [target for target in matching_targets if _target_specificity(target) == best_specificity]

        if len(best_targets) > 1:
            logger.warning(
                "Ambiguous proxy match for https://{}:{}{} — matched connections: {}. Forwarding unchanged.",
                normalized_host,
                port,
                path,
                ", ".join(f"{target.match.provider}/{target.match.connection}" for target in best_targets),
            )
            return None
        return best_targets[0].match

    @staticmethod
    def _build_routes(
        client: ProxyClient,
    ) -> tuple[dict[str, tuple[_RouteTarget, ...]], tuple[_RegexRouteTarget, ...]]:
        routes_by_host: dict[str, list[_RouteTarget]] = {}
        regex_routes: list[_RegexRouteTarget] = []
        from authsome.auth.models.provider import ProviderDefinition

        if hasattr(client, "proxy_routes"):
            try:
                route_data = client.proxy_routes()
                for route in route_data.get("routes", []):
                    route_match = RouteMatch(provider=route["provider"], connection=route.get("connection"))
                    regex_pattern = _compile_host_regex(route["host_url"])
                    auth_paths = frozenset(route.get("auth_endpoint_paths", []))
                    if regex_pattern is not None:
                        regex_routes.append(
                            _RegexRouteTarget(
                                host_pattern=regex_pattern,
                                target=_RouteTarget(
                                    match=route_match,
                                    path_prefix=None,
                                    auth_endpoint_paths=auth_paths,
                                    host_specificity=_HOST_SPECIFICITY_REGEX,
                                ),
                            )
                        )
                        continue
                    host, path_prefix = _parse_host_url(route["host_url"])
                    if not host or host in _LOOPBACK_HOSTS:
                        continue
                    routes_by_host.setdefault(host, []).append(
                        _RouteTarget(
                            match=route_match,
                            path_prefix=path_prefix,
                            auth_endpoint_paths=auth_paths,
                            host_specificity=_HOST_SPECIFICITY_EXACT,
                        )
                    )
                return {host: tuple(routes) for host, routes in routes_by_host.items()}, tuple(regex_routes)
            except Exception as exc:
                logger.warning("Could not load daemon proxy routes, falling back to local route build: {}", exc)

        connections_data = client.list_connections()
        for provider_group in connections_data["connections"]:
            provider_name = provider_group["name"]
            selected_connections = provider_group["connections"]

            try:
                definition_dict = client.get_provider(provider_name)
                definition = ProviderDefinition.model_validate(definition_dict)
            except Exception as exc:
                logger.warning("Skipping proxy routes for provider {}: {}", provider_name, exc)
                continue

            for conn in selected_connections:
                target_host_url = conn.get("host_url")
                if not target_host_url:
                    continue

                resolved = definition.resolve_urls(conn.get("base_url"))
                route_match = RouteMatch(provider=provider_name, connection=conn.get("connection_name"))
                regex_pattern = _compile_host_regex(target_host_url)
                if regex_pattern is not None:
                    regex_routes.append(
                        _RegexRouteTarget(
                            host_pattern=regex_pattern,
                            target=_RouteTarget(
                                match=route_match,
                                path_prefix=None,
                                auth_endpoint_paths=_auth_endpoint_paths_for_regex(resolved, regex_pattern),
                                host_specificity=_HOST_SPECIFICITY_REGEX,
                            ),
                        )
                    )
                    continue

                host, path_prefix = _parse_host_url(target_host_url)
                if not host or host in _LOOPBACK_HOSTS:
                    continue

                auth_endpoint_paths = _auth_endpoint_paths(resolved, host)
                routes_by_host.setdefault(host, []).append(
                    _RouteTarget(
                        match=route_match,
                        path_prefix=path_prefix,
                        auth_endpoint_paths=auth_endpoint_paths,
                        host_specificity=_HOST_SPECIFICITY_EXACT,
                    )
                )

        return {host: tuple(routes) for host, routes in routes_by_host.items()}, tuple(regex_routes)


def _route(client: ProxyClient, scheme: str, host: str, port: int, path: str) -> RouteMatch | None:
    """Return a RouteMatch when exactly one connected provider matches the request.

    Returns None for loopback targets, OAuth endpoints, zero matches, or ambiguous matches.
    """
    return ProxyRouter(client).route(scheme, host, port, path)


def _is_auth_endpoint(provider, host: str, path: str) -> bool:
    return _request_path(path) in _auth_endpoint_paths(provider, _normalize_host(host))


def _extract_host(host_url: str) -> str:
    return _parse_host_url(host_url)[0]


def _parse_host_url(host_url: str) -> tuple[str, str | None]:
    raw = host_url.strip()
    parsed = urlparse(raw if "://" in raw else f"//{raw}")
    host = _normalize_host(parsed.hostname or raw)
    return host, _normalize_path_prefix(parsed.path)


def _compile_host_regex(host_url: str) -> re.Pattern[str] | None:
    raw = host_url.strip()
    if not raw.lower().startswith(_REGEX_HOST_PREFIX):
        return None

    pattern = raw[len(_REGEX_HOST_PREFIX) :].strip()
    if not pattern:
        logger.warning("Skipping empty regex host_url")
        return None
    try:
        return re.compile(pattern, re.IGNORECASE)
    except re.error as exc:
        logger.warning("Skipping invalid regex host_url {}: {}", pattern, exc)
        return None


def _normalize_host(host: str) -> str:
    return host.strip().strip("[]").lower()


def _request_path(path: str) -> str:
    return urlparse(path).path or "/"


def _normalize_path_prefix(path: str | None) -> str | None:
    if not path or path == "/":
        return None
    return path.rstrip("/")


def _path_matches_prefix(request_path: str, path_prefix: str | None) -> bool:
    if path_prefix is None:
        return True
    return request_path == path_prefix or request_path.startswith(f"{path_prefix}/")


def _path_prefix_specificity(path_prefix: str | None) -> int:
    return len(path_prefix or "")


def _target_specificity(target: _RouteTarget) -> tuple[int, int]:
    return _path_prefix_specificity(target.path_prefix), target.host_specificity


def _auth_endpoint_paths(provider, host: str) -> frozenset[str]:
    if not provider.oauth:
        return frozenset()

    paths: set[str] = set()
    for raw_url in [
        provider.oauth.authorization_url,
        provider.oauth.token_url,
        provider.oauth.revocation_url,
        provider.oauth.device_authorization_url,
    ]:
        if not raw_url:
            continue
        parsed = urlparse(raw_url)
        if parsed.hostname and _normalize_host(parsed.hostname) == host:
            paths.add(parsed.path or "/")
    return frozenset(paths)


def _auth_endpoint_paths_for_regex(provider, host_pattern: re.Pattern[str]) -> frozenset[str]:
    if not provider.oauth:
        return frozenset()

    paths: set[str] = set()
    for raw_url in [
        provider.oauth.authorization_url,
        provider.oauth.token_url,
        provider.oauth.revocation_url,
        provider.oauth.device_authorization_url,
    ]:
        if not raw_url:
            continue
        parsed = urlparse(raw_url)
        if parsed.hostname and host_pattern.fullmatch(_normalize_host(parsed.hostname)):
            paths.add(parsed.path or "/")
    return frozenset(paths)


class AuthProxyAddon:
    """Mitmproxy addon that injects auth headers for matched requests.

    Credential resolution goes through the runtime client.
    """

    def __init__(self, client: ProxyClient) -> None:
        self._client = client
        self._router = ProxyRouter(client)
        self._header_cache: dict[tuple[str, str], _HeaderCacheEntry] = {}
        self._header_locks: dict[tuple[str, str], threading.Lock] = {}

    def request(self, flow: http.HTTPFlow) -> None:
        match = self._router.route(flow.request.scheme, flow.request.host, flow.request.port, flow.request.path)
        if match is None:
            return

        try:
            headers = self._get_auth_headers(match)
        except Exception:
            logger.warning(
                "Failed to retrieve auth headers for provider={} connection={}. Forwarding unchanged.",
                match.provider,
                match.connection,
            )
            return

        for key, value in headers.items():
            flow.request.headers[key] = value

    def _get_auth_headers(self, match: RouteMatch) -> dict[str, str]:
        cache_key = (match.provider, match.connection or "")
        now = utc_now()
        cached = self._header_cache.get(cache_key)
        if cached and _header_cache_valid(cached, now):
            return cached.headers.copy()

        lock = self._header_locks.setdefault(cache_key, threading.Lock())
        with lock:
            now = utc_now()
            cached = self._header_cache.get(cache_key)
            if cached and _header_cache_valid(cached, now):
                return cached.headers.copy()

            # Resolve through runtime client
            headers_resp = self._client.resolve_credentials(
                provider=match.provider,
                connection=match.connection,
            )
            headers = headers_resp["headers"]
            expires_at_raw = headers_resp.get("expires_at")
            expires_at = (
                datetime.fromisoformat(expires_at_raw.replace("Z", "+00:00"))
                if isinstance(expires_at_raw, str)
                else expires_at_raw
            )

            self._header_cache[cache_key] = _HeaderCacheEntry(
                headers=headers.copy(),
                expires_at=expires_at,
            )
            return headers


def _header_cache_valid(entry: _HeaderCacheEntry, now: datetime) -> bool:
    if entry.expires_at is None:
        return True
    return now < entry.expires_at - _HEADER_REFRESH_WINDOW


class RunningProxy:
    """Handle for a proxy running in a background thread."""

    def __init__(self, url: str, master: DumpMaster, thread: threading.Thread, confdir: Path) -> None:
        self.url = url
        self.master = master
        self.thread = thread
        self.confdir = confdir

    @property
    def ca_cert_path(self) -> Path:
        """Path to the mitmproxy CA certificate (PEM format)."""
        return self.confdir / "mitmproxy-ca-cert.pem"

    def shutdown(self) -> None:
        self.master.shutdown()
        self.thread.join(timeout=5)


class _ProxyReadyAddon:
    def __init__(self, ready: threading.Event, state: dict, host: str, port: int) -> None:
        self._ready = ready
        self._state = state
        self._host = host
        self._port = port

    def running(self) -> None:
        bound_host, bound_port = _resolve_listen_address(self._host, self._port)
        self._state["url"] = f"http://{_format_proxy_url_host(bound_host)}:{bound_port}"
        self._ready.set()


def _resolve_listen_address(fallback_host: str, fallback_port: int) -> tuple[str, int]:
    master = getattr(mitmproxy_ctx, "master", None)
    proxyserver = master.addons.get("proxyserver") if master else None
    listen_addrs = proxyserver.listen_addrs() if proxyserver else []
    if not listen_addrs:
        return fallback_host, fallback_port

    host, port = listen_addrs[0]
    if host in {"", "0.0.0.0", "::"}:
        host = fallback_host or "127.0.0.1"
    return str(host), int(port)


def _format_proxy_url_host(host: str) -> str:
    return f"[{host}]" if ":" in host and not host.startswith("[") else host


def _build_proxy_options(host: str, port: int, confdir: Path) -> Options:
    return Options(
        listen_host=host,
        listen_port=port,
        ssl_insecure=False,
        confdir=str(confdir),
    )


def start_proxy_server(
    client: ProxyClient,
    host: str = "127.0.0.1",
    port: int = 0,
) -> RunningProxy:
    """Start a mitmproxy DumpMaster in a background thread."""
    import asyncio

    confdir = Path.home() / ".mitmproxy"
    auth_addon = AuthProxyAddon(client=client)

    ready = threading.Event()
    state: dict = {}

    def _run() -> None:
        async def _async_main() -> None:
            opts = _build_proxy_options(host, port, confdir)
            master = DumpMaster(opts, with_termlog=False, with_dumper=False)
            master.addons.add(auth_addon)
            master.addons.add(_ProxyReadyAddon(ready=ready, state=state, host=host, port=port))
            state["master"] = master
            await master.run()

        try:
            asyncio.run(_async_main())
        except Exception as exc:
            state["error"] = exc
            ready.set()

    thread = threading.Thread(target=_run, daemon=True)
    thread.start()

    if not ready.wait(timeout=10):
        raise RuntimeError("Proxy server failed to initialize within 10 s")
    if "error" in state:
        raise RuntimeError("Proxy server failed to initialize") from state["error"]
    if "master" not in state or "url" not in state:
        raise RuntimeError("Proxy server failed to publish its listen address")

    url = state["url"]
    logger.info("Proxy server listening on {}", url)
    return RunningProxy(url=url, master=state["master"], thread=thread, confdir=confdir)

