"""Local daemon process control for CLI commands."""

from __future__ import annotations

import json
import os
import signal
import subprocess
import sys
import time
from pathlib import Path
from typing import Any

from authsome.cli.client import (
    DEFAULT_DAEMON_URL,
    AuthsomeApiClient,
    is_managed_local_daemon_url,
    resolve_daemon_url,
)
from authsome.server.daemon import DEFAULT_HOST, DEFAULT_PORT

AUTHSOME_HOME = Path(os.environ.get("AUTHSOME_HOME", str(Path.home() / ".authsome")))
DAEMON_DIR = AUTHSOME_HOME / "daemon"
PID_FILE = DAEMON_DIR / "daemon.pid"
LOG_FILE = DAEMON_DIR / "daemon.log"
STATE_FILE = DAEMON_DIR / "daemon.json"


class DaemonUnavailableError(RuntimeError):
    """Raised when the local daemon cannot be started or reached."""


def ensure_daemon() -> AuthsomeApiClient:
    """Return a ready daemon client, starting/restarting the daemon if needed."""
    client = AuthsomeApiClient(DEFAULT_DAEMON_URL)
    if _is_ready(client):
        return client
    if _pid_file_process_alive():
        stop_daemon()
    start_daemon()
    deadline = time.monotonic() + 10
    while time.monotonic() < deadline:
        if _is_ready(client):
            return client
        time.sleep(0.2)
    raise DaemonUnavailableError(_startup_error())


def resolve_runtime_client() -> AuthsomeApiClient:
    """Return the configured runtime client, auto-starting only for local mode."""
    client = AuthsomeApiClient(resolve_daemon_url())
    if is_managed_local_daemon_url(client.base_url):
        return ensure_daemon()
    return client


def start_daemon() -> None:
    DAEMON_DIR.mkdir(parents=True, exist_ok=True)
    log = LOG_FILE.open("ab")
    process = subprocess.Popen(
        [sys.executable, "-m", "authsome.cli.main", "daemon", "serve"],
        stdout=log,
        stderr=log,
        start_new_session=True,
    )
    PID_FILE.write_text(str(process.pid), encoding="utf-8")
    STATE_FILE.write_text(
        json.dumps({"pid": process.pid, "host": DEFAULT_HOST, "port": DEFAULT_PORT}, indent=2),
        encoding="utf-8",
    )


def stop_daemon() -> None:
    pid = _read_pid()
    if pid is None:
        return
    try:
        os.kill(pid, signal.SIGTERM)
    except ProcessLookupError:
        _clear_daemon_files()
        return
    deadline = time.monotonic() + 5
    while time.monotonic() < deadline:
        if not _process_alive(pid):
            _clear_daemon_files()
            return
        time.sleep(0.2)
    try:
        os.kill(pid, signal.SIGKILL)
    except ProcessLookupError:
        pass
    _clear_daemon_files()


def daemon_status() -> dict[str, Any]:
    client = AuthsomeApiClient(DEFAULT_DAEMON_URL)
    try:
        health = client.health()
        ready = client.ready()
        return {"running": True, "health": health, "ready": ready, "pid_file": str(PID_FILE), "log_file": str(LOG_FILE)}
    except Exception as exc:
        return {"running": False, "error": str(exc), "pid_file": str(PID_FILE), "log_file": str(LOG_FILE)}


def _is_ready(client: AuthsomeApiClient) -> bool:
    try:
        return client.health().get("status") == "ok" and client.ready().get("status") == "ready"
    except Exception:
        return False


def _read_pid() -> int | None:
    try:
        return int(PID_FILE.read_text(encoding="utf-8").strip())
    except Exception:
        return None


def _process_alive(pid: int) -> bool:
    try:
        os.kill(pid, 0)
        return True
    except OSError:
        return False


def _pid_file_process_alive() -> bool:
    pid = _read_pid()
    return pid is not None and _process_alive(pid)


def _clear_daemon_files() -> None:
    for path in (PID_FILE, STATE_FILE):
        try:
            path.unlink()
        except FileNotFoundError:
            pass


def _startup_error() -> str:
    lines: list[str] = []
    if LOG_FILE.exists():
        lines = LOG_FILE.read_text(encoding="utf-8", errors="replace").splitlines()[-12:]
    detail = "\n".join(lines) if lines else "No daemon log output was captured."
    return f"Authsome daemon failed to start.\nLog: {LOG_FILE}\n\n{detail}"

"""Internal HTTP client used by the CLI and local proxy runner."""

from __future__ import annotations

import os
from collections.abc import Mapping
from typing import Any
from urllib.parse import urlparse

import requests

from authsome.server.urls import DEFAULT_SERVER_BASE_URL

DEFAULT_DAEMON_URL = DEFAULT_SERVER_BASE_URL


def resolve_daemon_url(env: Mapping[str, str] | None = None) -> str:
    """Return the configured daemon URL for CLI and proxy clients."""
    values = env if env is not None else os.environ
    raw = values.get("AUTHSOME_DAEMON_URL", DEFAULT_DAEMON_URL).strip()
    return raw.rstrip("/") or DEFAULT_DAEMON_URL


def is_local_daemon_url(url: str) -> bool:
    """Return whether the configured daemon URL targets a local loopback daemon."""
    hostname = urlparse(url).hostname
    return hostname in {"127.0.0.1", "localhost", "::1"}


def is_managed_local_daemon_url(url: str) -> bool:
    """Return whether the URL matches the default local daemon managed by the CLI."""
    parsed = urlparse(url)
    if parsed.scheme != "http":
        return False
    if parsed.path not in {"", "/"}:
        return False
    return parsed.hostname in {"127.0.0.1", "localhost", "::1"} and (parsed.port in {None, 7998})


def raise_for_error(response: requests.Response) -> None:
    try:
        response.raise_for_status()
    except requests.HTTPError as exc:
        obj = None
        try:
            data = response.json()
            error_name = data.get("error")
            message = data.get("message")
            if error_name and message:
                import authsome.errors as err_mod

                exc_cls = getattr(err_mod, error_name, None)
                if exc_cls and issubclass(exc_cls, err_mod.AuthsomeError):
                    obj = exc_cls.__new__(exc_cls)
                    Exception.__init__(obj, message)
                    obj.provider = data.get("provider")
                    obj.operation = data.get("operation")
        except Exception:
            pass

"""Unified storage interfaces for Authsome.

This module defines the abstract boundaries for all persistence in Authsome.
A single `AppStore` interface groups config, profiles, providers, and
vault KV storage, allowing the entire storage backend to be swapped out
for remote environments.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from pathlib import Path
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from authsome.auth.models.config import GlobalConfig
    from authsome.auth.models.profile import ProfileMetadata
    from authsome.auth.models.provider import ProviderDefinition


class VaultStorage(ABC):
    """Abstract key-value storage backend for a single profile's vault."""

    @abstractmethod
    def get(self, key: str) -> str | None:
        """Retrieve a value by key. Returns None if not found."""
        ...

    @abstractmethod
    def put(self, key: str, value: str) -> None:
        """Store a value by key (upsert)."""
        ...

    @abstractmethod
    def delete(self, key: str) -> bool:
        """Delete a key. Returns True if the key existed."""
        ...

    @abstractmethod
    def list_keys(self, prefix: str = "") -> list[str]:
        """List all keys matching a prefix."""
        ...

    @abstractmethod
    def close(self) -> None:
        """Release any resources held by the backend."""
        ...


class AppStore(ABC):
    """Unified storage interface for all Authsome persistence."""

    @property
    @abstractmethod
    def home(self) -> Path:
        """Get the base directory for this storage system."""
        ...

    # ── Initialization ────────────────────────────────────────────────────

    @abstractmethod
    def ensure_initialized(self) -> None:
        """Ensure the storage system is initialized (e.g. default profile exists)."""
        ...

    @abstractmethod
    def is_healthy(self) -> bool:
        """Check if the store is accessible and healthy."""
        ...

    # ── Config ────────────────────────────────────────────────────────────

    @abstractmethod
    def get_config(self) -> GlobalConfig:
        """Get global configuration."""
        ...

    @abstractmethod
    def save_config(self, config: GlobalConfig) -> None:
        """Save global configuration."""
        ...

    # ── Profiles ──────────────────────────────────────────────────────────

    @abstractmethod
    def get_profile(self, name: str) -> ProfileMetadata:
        """Get profile metadata. Raises ProfileNotFoundError if missing."""
        ...

    @abstractmethod
    def save_profile(self, metadata: ProfileMetadata) -> None:
        """Save profile metadata."""
        ...

    @abstractmethod
    def list_profiles(self) -> list[ProfileMetadata]:
        """List all profiles."""
        ...

    @abstractmethod
    def delete_profile(self, name: str) -> None:
        """Delete a profile and its vault."""
        ...

    # ── Providers ─────────────────────────────────────────────────────────

    @abstractmethod
    def get_provider(self, name: str) -> ProviderDefinition:
        """Get a custom provider definition. Raises ProviderNotFoundError if missing."""
        ...

    @abstractmethod
    def save_provider(self, definition: ProviderDefinition) -> None:
        """Save a custom provider definition."""
        ...

    @abstractmethod
    def list_providers(self) -> list[ProviderDefinition]:
        """List all custom providers."""
        ...

    @abstractmethod
    def delete_provider(self, name: str) -> None:
        """Delete a custom provider definition."""
        ...

    # ── Vault ─────────────────────────────────────────────────────────────

    @abstractmethod
    def get_vault_storage(self, profile: str) -> VaultStorage:
        """Get the KV storage backend for a specific profile's vault."""
        ...

    @abstractmethod
    def close(self) -> None:
        """Close all underlying storage connections."""
        ...

